import{_ as a,o,c as t,ag as i}from"./chunks/framework.BqKFDx7z.js";const u=JSON.parse('{"title":"Roadmap","description":"Planned and in-progress features for TalaDB ‚Äî query engine improvements, sync, developer tooling, and new platform targets.","frontmatter":{"title":"Roadmap","description":"Planned and in-progress features for TalaDB ‚Äî query engine improvements, sync, developer tooling, and new platform targets."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),r={name:"roadmap.md"};function n(d,e,l,s,c,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">‚Äã</a></h1><p>This page tracks planned and in-progress work for TalaDB. Items are grouped by theme and ordered roughly by priority within each group. The list is updated as the project evolves.</p><p>Have an idea or want to help prioritise? Open a <a href="https://github.com/thinkgrid-labs/taladb/discussions" target="_blank" rel="noreferrer">GitHub Discussion</a> or a feature request issue.</p><hr><h2 id="in-progress" tabindex="-1">In progress <a class="header-anchor" href="#in-progress" aria-label="Permalink to &quot;In progress&quot;">‚Äã</a></h2><h3 id="react-native-‚Äî-full-ios-android-turbomodule-integration" tabindex="-1">React Native ‚Äî full iOS + Android TurboModule integration <a class="header-anchor" href="#react-native-‚Äî-full-ios-android-turbomodule-integration" aria-label="Permalink to &quot;React Native ‚Äî full iOS + Android TurboModule integration&quot;">‚Äã</a></h3><p>The C FFI layer (<code>taladb-ffi</code>) and C++ JSI HostObject are complete. The remaining work is wiring the Xcode build phase (universal <code>.a</code> via <code>lipo</code>) and the Android Gradle AAR packaging so that <code>pod install</code> / Gradle are the only steps a consumer needs.</p><h3 id="or-index-union-across-different-fields" tabindex="-1"><code>$or</code> index union across different fields <a class="header-anchor" href="#or-index-union-across-different-fields" aria-label="Permalink to &quot;`$or` index union across different fields&quot;">‚Äã</a></h3><p>The query planner currently handles <code>$or</code> across multiple values of the <strong>same</strong> field (e.g. <code>role = &#39;admin&#39; OR role = &#39;editor&#39;</code>). The next step is merging results from <strong>different</strong> indexed fields (e.g. <code>status = &#39;pinned&#39; OR priority = 1</code>) using a sorted-merge join on ULIDs.</p><h3 id="cli-interactive-shell" tabindex="-1">CLI interactive shell <a class="header-anchor" href="#cli-interactive-shell" aria-label="Permalink to &quot;CLI interactive shell&quot;">‚Äã</a></h3><p><code>taladb shell &lt;file&gt;</code> ‚Äî a REPL that accepts filter expressions in JSON, displays results as formatted tables, and supports tab-completion for collection and field names.</p><hr><h2 id="query-engine" tabindex="-1">Query engine <a class="header-anchor" href="#query-engine" aria-label="Permalink to &quot;Query engine&quot;">‚Äã</a></h2><h3 id="compound-indexes" tabindex="-1">Compound indexes <a class="header-anchor" href="#compound-indexes" aria-label="Permalink to &quot;Compound indexes&quot;">‚Äã</a></h3><p>Index a tuple of fields <code>(lastName, firstName)</code> so that queries with equality on <code>lastName</code> and a range on <code>firstName</code> use a single B-tree scan instead of two separate index scans with an in-memory join.</p><h3 id="aggregation-pipeline" tabindex="-1">Aggregation pipeline <a class="header-anchor" href="#aggregation-pipeline" aria-label="Permalink to &quot;Aggregation pipeline&quot;">‚Äã</a></h3><p>A lightweight <code>aggregate()</code> method supporting <code>$group</code>, <code>$sum</code>, <code>$avg</code>, <code>$min</code>, <code>$max</code>, <code>$count</code>, and <code>$sort</code> ‚Äî enough to power dashboards and analytics views without moving data out of the database.</p><h3 id="projection" tabindex="-1">Projection <a class="header-anchor" href="#projection" aria-label="Permalink to &quot;Projection&quot;">‚Äã</a></h3><p><code>find(filter, { fields: [&#39;name&#39;, &#39;email&#39;] })</code> ‚Äî return only specified fields, reducing deserialization cost for wide documents with many fields.</p><h3 id="cursor-pagination" tabindex="-1">Cursor / pagination <a class="header-anchor" href="#cursor-pagination" aria-label="Permalink to &quot;Cursor / pagination&quot;">‚Äã</a></h3><p><code>find(filter, { skip: 0, limit: 20, sort: { createdAt: -1 } })</code> ‚Äî stable, index-aware pagination without loading the entire result set into memory.</p><h3 id="regex-filter" tabindex="-1"><code>$regex</code> filter <a class="header-anchor" href="#regex-filter" aria-label="Permalink to &quot;`$regex` filter&quot;">‚Äã</a></h3><p>Pattern matching against string fields using a compiled regex. Evaluated as a post-filter (no index support) but useful for search and validation.</p><h3 id="nested-field-queries" tabindex="-1">Nested field queries <a class="header-anchor" href="#nested-field-queries" aria-label="Permalink to &quot;Nested field queries&quot;">‚Äã</a></h3><p>Dot-notation access to nested object fields ‚Äî <code>{ &#39;address.city&#39;: &#39;London&#39; }</code> ‚Äî without requiring the caller to flatten documents before inserting.</p><hr><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">‚Äã</a></h2><h3 id="write-ahead-log-compaction" tabindex="-1">Write-ahead log compaction <a class="header-anchor" href="#write-ahead-log-compaction" aria-label="Permalink to &quot;Write-ahead log compaction&quot;">‚Äã</a></h3><p>redb already handles WAL compaction internally, but exposing a <code>db.compact()</code> API for explicit compaction (e.g. after bulk deletes) would let long-running applications reclaim disk space on demand.</p><h3 id="pluggable-serialisation" tabindex="-1">Pluggable serialisation <a class="header-anchor" href="#pluggable-serialisation" aria-label="Permalink to &quot;Pluggable serialisation&quot;">‚Äã</a></h3><p>Allow the caller to swap <code>postcard</code> for <code>MessagePack</code> or <code>CBOR</code> via a <code>Codec</code> trait, making it easier to interoperate with databases or wire formats that already use those encodings.</p><h3 id="indexeddb-fallback-backend" tabindex="-1">IndexedDB fallback backend <a class="header-anchor" href="#indexeddb-fallback-backend" aria-label="Permalink to &quot;IndexedDB fallback backend&quot;">‚Äã</a></h3><p>A complete <code>StorageBackend</code> implementation on top of IndexedDB for browsers that will never support OPFS (e.g. cross-origin iframes). Currently the fallback is in-memory only.</p><hr><h2 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">‚Äã</a></h2><h3 id="conflict-free-sync-with-crdts" tabindex="-1">Conflict-free sync with CRDTs <a class="header-anchor" href="#conflict-free-sync-with-crdts" aria-label="Permalink to &quot;Conflict-free sync with CRDTs&quot;">‚Äã</a></h3><p>A <code>CrdtSyncAdapter</code> that uses per-field logical clocks (LWW-register or grow-only sets) to merge concurrent writes from multiple devices without conflicts ‚Äî suitable for collaborative offline-first apps.</p><h3 id="sync-over-websockets" tabindex="-1">Sync over WebSockets <a class="header-anchor" href="#sync-over-websockets" aria-label="Permalink to &quot;Sync over WebSockets&quot;">‚Äã</a></h3><p>A reference sync server (<code>taladb-sync-server</code>) that accepts snapshot diffs over a WebSocket connection and applies <code>LastWriteWins</code> or CRDT merge logic server-side, enabling multi-device sync without a cloud database.</p><h3 id="delta-snapshots" tabindex="-1">Delta snapshots <a class="header-anchor" href="#delta-snapshots" aria-label="Permalink to &quot;Delta snapshots&quot;">‚Äã</a></h3><p>Instead of exporting the full database on every sync, export only the records that changed since a given ULID watermark ‚Äî reducing bandwidth for incremental sync scenarios.</p><hr><h2 id="developer-experience" tabindex="-1">Developer experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer experience&quot;">‚Äã</a></h2><h3 id="taladb-generate-‚Äî-typescript-type-generation" tabindex="-1"><code>taladb generate</code> ‚Äî TypeScript type generation <a class="header-anchor" href="#taladb-generate-‚Äî-typescript-type-generation" aria-label="Permalink to &quot;`taladb generate` ‚Äî TypeScript type generation&quot;">‚Äã</a></h3><p>Inspect a live database and emit TypeScript interfaces for each collection, inferred from the stored documents. Useful for projects that don&#39;t start with a schema.</p><h3 id="taladb-studio-‚Äî-local-web-ui" tabindex="-1"><code>taladb studio</code> ‚Äî local web UI <a class="header-anchor" href="#taladb-studio-‚Äî-local-web-ui" aria-label="Permalink to &quot;`taladb studio` ‚Äî local web UI&quot;">‚Äã</a></h3><p>A browser-based GUI (served by <code>taladb-cli</code>) for browsing collections, running ad-hoc queries, inspecting indexes, and visualising query plans ‚Äî similar to MongoDB Compass but for local files.</p><h3 id="react-hooks-package-taladb-react" tabindex="-1">React hooks package (<code>@taladb/react</code>) <a class="header-anchor" href="#react-hooks-package-taladb-react" aria-label="Permalink to &quot;React hooks package (`@taladb/react`)&quot;">‚Äã</a></h3><p>First-party <code>useCollection</code>, <code>useWatch</code>, <code>useFind</code>, and <code>useFindOne</code> hooks that integrate with React&#39;s <code>useSyncExternalStore</code> for zero-tearing live query snapshots in concurrent React.</p><h3 id="zod-valibot-schema-validation" tabindex="-1">Zod / Valibot schema validation <a class="header-anchor" href="#zod-valibot-schema-validation" aria-label="Permalink to &quot;Zod / Valibot schema validation&quot;">‚Äã</a></h3><p>An optional <code>schema</code> option on <code>collection()</code> that validates documents with a Zod or Valibot schema before insert and after find, providing runtime type safety without a compile step.</p><h3 id="vs-code-extension" tabindex="-1">VS Code extension <a class="header-anchor" href="#vs-code-extension" aria-label="Permalink to &quot;VS Code extension&quot;">‚Äã</a></h3><p>Syntax highlighting for TalaDB filter expressions in JSON, inline document previews, and a collection browser panel in the VS Code sidebar.</p><hr><h2 id="platform" tabindex="-1">Platform <a class="header-anchor" href="#platform" aria-label="Permalink to &quot;Platform&quot;">‚Äã</a></h2><h3 id="cloudflare-workers-deno-deploy" tabindex="-1">Cloudflare Workers / Deno Deploy <a class="header-anchor" href="#cloudflare-workers-deno-deploy" aria-label="Permalink to &quot;Cloudflare Workers / Deno Deploy&quot;">‚Äã</a></h3><p>A <code>StorageBackend</code> implementation backed by Cloudflare&#39;s <code>KV</code> or <code>Durable Objects</code> API, letting TalaDB run as the persistence layer inside an edge function with zero external dependencies.</p><h3 id="bun-native-module" tabindex="-1">Bun native module <a class="header-anchor" href="#bun-native-module" aria-label="Permalink to &quot;Bun native module&quot;">‚Äã</a></h3><p>A Bun-native binding (using Bun&#39;s <code>bun:ffi</code>) that avoids the N-API layer for better startup performance and smaller binary size in Bun-first projects.</p><h3 id="swift-kotlin-native-packages" tabindex="-1">Swift / Kotlin native packages <a class="header-anchor" href="#swift-kotlin-native-packages" aria-label="Permalink to &quot;Swift / Kotlin native packages&quot;">‚Äã</a></h3><p>First-party Swift (<code>TalaDB.swift</code>) and Kotlin (<code>taladb-kotlin</code>) packages that wrap the C FFI layer directly, without React Native, for native iOS and Android apps that want an embedded document store.</p><h3 id="wasi-target" tabindex="-1">WASI target <a class="header-anchor" href="#wasi-target" aria-label="Permalink to &quot;WASI target&quot;">‚Äã</a></h3><p>Compile <code>taladb-core</code> to WASI (<code>wasm32-wasip1</code>) so it can run inside WASI runtimes (Wasmtime, WasmEdge, Fastly Compute) with filesystem access ‚Äî bringing the same engine to server-side WASM environments.</p><hr><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">‚Äã</a></h2><h3 id="key-rotation" tabindex="-1">Key rotation <a class="header-anchor" href="#key-rotation" aria-label="Permalink to &quot;Key rotation&quot;">‚Äã</a></h3><p>A <code>db.rekey(newKey)</code> method that re-encrypts all stored values in a single atomic transaction without requiring an export/import cycle.</p><h3 id="field-level-encryption" tabindex="-1">Field-level encryption <a class="header-anchor" href="#field-level-encryption" aria-label="Permalink to &quot;Field-level encryption&quot;">‚Äã</a></h3><p>Encrypt individual fields rather than entire values, so that unencrypted fields can still be indexed and used in range queries while sensitive fields (e.g. <code>ssn</code>, <code>creditCard</code>) are protected at rest.</p><h3 id="audit-log" tabindex="-1">Audit log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit log&quot;">‚Äã</a></h3><p>An append-only <code>_audit</code> collection that records every write operation (collection, document ID, operation type, timestamp) ‚Äî opt-in, with configurable retention.</p>',71)])])}const f=a(r,[["render",n]]);export{u as __pageData,f as default};
